print("=== DEOBFUSCATOR INICIADO ===")

local old_loadstring = loadstring
local old_getfenv = getfenv

local dumped_payload = ""

getfenv = function(...)
    local env = old_getfenv and old_getfenv(...) or _ENV
    env.loadstring = function(code)
        if type(code) == "string" and #code > 500 then
            dumped_payload = code
            print(":white_check_mark: PAYLOAD CAPTURADO (" .. #code .. " caracteres)")
            writefile("payload_limpio.lua", code)
            print(":floppy_disk: Archivo guardado: payload_limpio.lua")
        end
        return old_loadstring(code)
    end
    return env
end

